  ('pukao-0c700c30-moex-00204', 'pukao-0c700c30', 'pukao-0c700c30-moex-111-6948958a', 'sub-pukao-0c700c30-02', NULL, 'single_choice', '一家獨占廠商面對的需求線是P=120-Q，其中P和Q分別代表市場的價格與需求量。這家廠商遞增的邊 際成本可以用MC(Q)=Q描述。如果它的目標在於追求最大的利潤，則它會將價格訂為：', '["120", "100", "80", "60"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:49+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "417", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "統計"}'::jsonb, NULL),
